// ===================================================
// WF-07 Step 1: POST 본문 파싱 + 입력값 검증 + URL sanitize
// 필수: name, studio_name, member_id, phone, email
// 선택: portfolio_url, instagram_url, specialty, location, introduction
// ===================================================

const input = $input.first().json;
const body = input.body || input;

// === HTML XSS 방지 ===
function escapeHtml(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/\"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

// === 텍스트 정제 (제어 문자 제거 + 길이 제한) ===
function sanitizeText(str, maxLen) {
  if (!str) return '';
  maxLen = maxLen || 500;
  return String(str)
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '')
    .trim()
    .substring(0, maxLen);
}

// === URL 검증 (http/https만 허용, javascript:/data: 등 차단) ===
function sanitizeUrl(url) {
  if (!url) return '';
  const trimmed = String(url).trim();
  if (!trimmed) return '';
  const lower = trimmed.toLowerCase();
  // http, https 허용
  if (lower.startsWith('http://') || lower.startsWith('https://')) {
    return trimmed.substring(0, 2048);
  }
  // 프로토콜 없는 경우 https 추가
  if (!lower.includes('://') && !lower.includes(':')) {
    return ('https://' + trimmed).substring(0, 2048);
  }
  // javascript:, data:, vbscript: 등 차단
  return '';
}

// === 필수 필드 검증 ===
const name = sanitizeText(body.name, 100);
const studioName = sanitizeText(body.studio_name, 100);
const memberId = sanitizeText(body.member_id, 100);
const phone = sanitizeText(body.phone, 20);
const email = sanitizeText(body.email, 200);

const missingFields = [];
if (!name) missingFields.push('name');
if (!studioName) missingFields.push('studio_name');
if (!memberId) missingFields.push('member_id');
if (!phone) missingFields.push('phone');
if (!email) missingFields.push('email');

if (missingFields.length > 0) {
  return [{
    json: {
      _valid: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'MISSING_PARAMS',
          message: missingFields.join(', ') + ' 파라미터가 필요합니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

// === 이메일 형식 검증 ===
if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
  return [{
    json: {
      _valid: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'INVALID_PARAMS',
          message: '유효한 email 형식이 필요합니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

// === 선택 필드 정제 ===
const portfolioUrl = sanitizeUrl(body.portfolio_url);
const instagramUrl = sanitizeUrl(body.instagram_url);
const specialty = sanitizeText(body.specialty, 100);
const location = sanitizeText(body.location, 100);
const introduction = sanitizeText(body.introduction, 500);

return [{
  json: {
    _valid: true,
    name,
    studioName,
    memberId,
    phone,
    email,
    portfolioUrl,
    instagramUrl,
    specialty,
    location,
    introduction,
    // XSS-safe 버전 (이메일 HTML용)
    _safe: {
      name: escapeHtml(name),
      studioName: escapeHtml(studioName),
      memberId: escapeHtml(memberId),
      phone: escapeHtml(phone),
      email: escapeHtml(email),
      specialty: escapeHtml(specialty),
      location: escapeHtml(location)
    }
  }
}];

// ===================================================
// WF-07 Step 2: 기존 파트너 여부 확인
// tbl_Partners에 member_id가 이미 있으면 중복
// boolean 비교 대신 문자열 상태값으로 후속 IF 안정화
// ===================================================

const response = $input.first().json;
const partnerList = response.list || [];
const validData = $('Validate Input').first().json;

if (partnerList.length > 0) {
  const existing = partnerList[0];
  return [{
    json: {
      ...validData,
      _partnerStatus: 'BLOCKED',
      _duplicateType: 'PARTNER',
      _errorResponse: {
        success: false,
        error: {
          code: 'ALREADY_PARTNER',
          message: '이미 파트너로 등록되어 있습니다.'
        },
        data: {
          partner_code: existing.partner_code || '',
          status: existing.status || ''
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

return [{
  json: {
    ...validData,
    _partnerStatus: 'CLEAR'
  }
}];

// ===================================================
// WF-07 Step 3: PENDING 신청 중복 확인
// tbl_Applications에 PENDING 상태인 신청이 있으면 중복
// boolean 비교 대신 문자열 상태값으로 후속 IF 안정화
// ===================================================

const response = $input.first().json;
const appList = response.list || [];
const prevData = $('Check Partner Exists').first().json;

if (appList.length > 0) {
  const existing = appList[0];
  return [{
    json: {
      ...prevData,
      _applicationStatus: 'BLOCKED',
      _duplicateType: 'APPLICATION',
      _errorResponse: {
        success: false,
        error: {
          code: 'DUPLICATE_APPLICATION',
          message: '이미 심사 중인 신청이 있습니다.'
        },
        data: {
          application_id: existing.application_id || '',
          status: 'PENDING'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

return [{
  json: {
    ...prevData,
    _applicationStatus: 'CLEAR'
  }
}];

// ===================================================
// WF-07 Step 4: application_id 생성 (APP_YYYYMMDD_XXXXXX)
// ===================================================

const prevData = $input.first().json;
const now = new Date();

// === application_id 생성: APP_YYYYMMDD_XXXXXX ===
const pad = (n) => String(n).padStart(2, '0');
const dateStr = String(now.getFullYear())
  + pad(now.getMonth() + 1)
  + pad(now.getDate());
const randomSuffix = String(Math.floor(100000 + Math.random() * 900000));
const applicationId = 'APP_' + dateStr + '_' + randomSuffix;

// === 한국 날짜 포맷 (이메일용) ===
const appliedDate = now.toISOString();
const appliedDateKR = now.getFullYear() + '년 '
  + (now.getMonth() + 1) + '월 '
  + now.getDate() + '일';

return [{
  json: {
    ...prevData,
    _applicationId: applicationId,
    _appliedDate: appliedDate,
    _appliedDateKR: appliedDateKR
  }
}];

// ===================================================
// WF-07 Step 5: NocoDB 레코드 생성 결과 확인
// ===================================================

const createResult = $input.first().json;
const prevData = $('Generate Application ID').first().json;

// NocoDB 레코드 생성 성공 확인 (Id 필드가 존재하면 성공)
const recordCreated = !!createResult.Id || !!createResult.id;

if (!recordCreated) {
  return [{
    json: {
      _success: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'APPLICATION_FAILED',
          message: '파트너 신청 저장에 실패했습니다. 잠시 후 다시 시도해 주세요.'
        },
        timestamp: new Date().toISOString()
      },
      _telegramError: '파트너 신청 저장 실패: ' + prevData.name + ' (' + prevData.memberId + ')'
    }
  }];
}

return [{
  json: {
    _success: true,
    ...prevData,
    _nocodbRecordId: createResult.Id || createResult.id
  }
}];

// ===================================================
// WF-07 Step 6a: 신청 접수 확인 이메일 HTML 생성
// brand-strategy-comprehensive.md 이메일 7 참고
// 브랜드 톤: 따뜻 + 안심 + 포용
// duplicate/error 경로에서도 안전하게 fallback 처리
// ===================================================

const data = $input.first().json;
const safeData = data._safe || {};
const s = {
  name: safeData.name || data.name || '',
  studioName: safeData.studioName || data.studioName || '',
  specialty: safeData.specialty || data.specialty || '',
  location: safeData.location || data.location || ''
};

const subject = '[PRESSCO21] 파트너 신청이 접수되었습니다';

const html = '<!DOCTYPE html><html lang="ko"><head><meta charset="UTF-8" /><meta name="viewport" content="width=device-width, initial-scale=1.0" /><title>PRESSCO21 파트너 신청 접수 확인</title></head>'
+ '<body style="margin: 0; padding: 0; background-color: #f8f6f0; font-family: \'Pretendard\', \'Apple SD Gothic Neo\', \'Malgun Gothic\', sans-serif;">'
+ '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #f8f6f0;"><tr><td align="center" style="padding: 24px 16px;">'
+ '<table width="600" cellpadding="0" cellspacing="0" border="0" style="max-width: 600px; width: 100%; background-color: #ffffff; border-radius: 8px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.06);">'
// 헤더
+ '<tr><td style="padding: 24px 32px; text-align: center; border-bottom: 2px solid #b89b5e;">'
+ '<span style="font-size: 22px; font-weight: 700; color: #b89b5e; letter-spacing: 2px;">PRESSCO21</span><br />'
+ '<span style="font-size: 11px; color: #999999; letter-spacing: 1px;">Forever and ever and Blooming</span>'
+ '</td></tr>'
// 본문
+ '<tr><td style="padding: 40px 32px 32px;">'
+ '<p style="margin: 0 0 24px; font-size: 15px; color: #333333; line-height: 1.7;"><strong style="color: #b89b5e;">' + s.name + '</strong>님, 안녕하세요!</p>'
+ '<p style="margin: 0 0 8px; font-size: 15px; color: #333333; line-height: 1.7;">PRESSCO21 블룸 파트너 프로그램에 관심을 가져주셔서</p>'
+ '<p style="margin: 0 0 32px; font-size: 15px; color: #333333; line-height: 1.7;">진심으로 감사합니다.</p>'
+ '<p style="margin: 0 0 32px; font-size: 15px; color: #333333; line-height: 1.7;">' + s.name + '님의 파트너 신청서가 정상적으로 접수되었습니다.</p>'
// 접수 정보 테이블
+ '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #faf8f3; border-radius: 8px; border: 1px solid #e8e4db; margin-bottom: 24px;">'
+ '<tr><td style="padding: 20px 24px 12px;"><p style="margin: 0 0 16px; font-size: 14px; font-weight: 700; color: #b89b5e; letter-spacing: 1px;">접수 정보</p></td></tr>'
+ '<tr><td style="padding: 0 24px;"><table width="100%" cellpadding="0" cellspacing="0" border="0">'
+ '<tr><td style="padding: 8px 0; font-size: 13px; color: #999999; width: 90px; vertical-align: top;">신청자</td><td style="padding: 8px 0; font-size: 14px; color: #333333; font-weight: 600;">' + s.name + '</td></tr>'
+ '<tr><td style="padding: 8px 0; font-size: 13px; color: #999999; vertical-align: top;">공방명</td><td style="padding: 8px 0; font-size: 14px; color: #333333;">' + s.studioName + '</td></tr>'
+ '<tr><td style="padding: 8px 0; font-size: 13px; color: #999999; vertical-align: top;">전문 분야</td><td style="padding: 8px 0; font-size: 14px; color: #333333;">' + (s.specialty || '-') + '</td></tr>'
+ '<tr><td style="padding: 8px 0; font-size: 13px; color: #999999; vertical-align: top;">활동 지역</td><td style="padding: 8px 0; font-size: 14px; color: #333333;">' + (s.location || '-') + '</td></tr>'
+ '<tr><td style="padding: 8px 0; font-size: 13px; color: #999999; vertical-align: top;">접수일</td><td style="padding: 8px 0; font-size: 14px; color: #333333;">' + data._appliedDateKR + '</td></tr>'
+ '</table></td></tr>'
+ '<tr><td style="padding: 12px 24px 16px;"><table width="100%" cellpadding="0" cellspacing="0" border="0" style="border-top: 1px solid #e8e4db;">'
+ '<tr><td style="padding: 12px 0 0; font-size: 12px; color: #999999;">접수 번호: ' + data._applicationId + '</td></tr>'
+ '</table></td></tr></table>'
// 다음 단계 안내
+ '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom: 24px;"><tr><td style="padding: 20px 24px; background-color: #fef9f0; border-radius: 8px; border-left: 3px solid #b89b5e;">'
+ '<p style="margin: 0 0 12px; font-size: 14px; font-weight: 700; color: #b89b5e;">다음 단계는 이렇게 진행돼요</p>'
+ '<table width="100%" cellpadding="0" cellspacing="0" border="0">'
+ '<tr><td style="padding: 6px 0; font-size: 14px; color: #555555; line-height: 1.6;"><strong style="color: #b89b5e;">1.</strong> 관리자 검토 (1~3 영업일)<br /><span style="font-size: 13px; color: #888888; padding-left: 16px;">제출해주신 정보와 포트폴리오를 확인합니다.</span></td></tr>'
+ '<tr><td style="padding: 6px 0; font-size: 14px; color: #555555; line-height: 1.6;"><strong style="color: #b89b5e;">2.</strong> 결과 안내 이메일 발송<br /><span style="font-size: 13px; color: #888888; padding-left: 16px;">검토가 완료되면 결과를 이메일로 안내해드릴게요.</span></td></tr>'
+ '<tr><td style="padding: 6px 0; font-size: 14px; color: #555555; line-height: 1.6;"><strong style="color: #b89b5e;">3.</strong> 승인 시 파트너 코드 발급<br /><span style="font-size: 13px; color: #888888; padding-left: 16px;">바로 교육을 이수하고 활동을 시작하실 수 있어요.</span></td></tr>'
+ '</table></td></tr></table>'
// 안심 메시지
+ '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom: 32px;"><tr><td style="padding: 16px 20px; background-color: #f5f5f5; border-radius: 8px;">'
+ '<p style="margin: 0; font-size: 13px; color: #888888; line-height: 1.6;">별도로 준비하실 것은 없습니다.<br />검토 결과가 나오면 바로 연락드릴게요!</p>'
+ '</td></tr></table>'
// 마무리
+ '<p style="margin: 0 0 8px; font-size: 15px; color: #333333; line-height: 1.7;">궁금하신 점이 있으시면</p>'
+ '<p style="margin: 0; font-size: 15px; color: #333333; line-height: 1.7;">pressco21@foreverlove.co.kr로 편하게 문의해주세요.</p>'
+ '</td></tr>'
// 서명
+ '<tr><td style="padding: 0 32px 32px;"><p style="margin: 0; font-size: 14px; color: #b89b5e; font-weight: 600;">PRESSCO21 드림</p></td></tr>'
// 푸터
+ '<tr><td style="padding: 24px 32px; text-align: center; background-color: #faf8f3; border-top: 1px solid #e8e4db;">'
+ '<p style="margin: 0 0 8px; font-size: 12px; color: #999999;">PRESSCO21 | foreverlove.co.kr</p>'
+ '<p style="margin: 0 0 8px; font-size: 12px; color: #999999;">문의: pressco21@foreverlove.co.kr</p>'
+ '<p style="margin: 0; font-size: 11px; color: #bbbbbb;">이 메일은 PRESSCO21 파트너 프로그램 관련 안내 메일입니다.</p>'
+ '</td></tr></table></td></tr></table></body></html>';

return [{
  json: {
    ...data,
    _confirmEmail: {
      to: data.email,
      subject,
      html
    }
  }
}];

// ===================================================
// WF-07 Step 6b: 텔레그램 관리자 알림 메시지 구성
// 관리자용이므로 개인정보 포함 (신청 검토에 필요)
// ===================================================

const data = $input.first().json;

const message = '[파트너 신청] 새 신청이 접수되었습니다\n\n'
  + '신청자: ' + data.name + '\n'
  + '공방명: ' + data.studioName + '\n'
  + '전문 분야: ' + (data.specialty || '-') + '\n'
  + '활동 지역: ' + (data.location || '-') + '\n'
  + '이메일: ' + data.email + '\n'
  + '접수 시각: ' + data._appliedDate + '\n'
  + '접수 번호: ' + data._applicationId + '\n'
  + (data.portfolioUrl ? '\n포트폴리오: ' + data.portfolioUrl : '')
  + (data.instagramUrl ? '\n인스타그램: ' + data.instagramUrl : '')
  + '\n\n-> NocoDB 파트너 신청 테이블에서 검토해주세요.';

return [{
  json: {
    ...data,
    _telegramMessage: message
  }
}];

// ===================================================
// WF-07 Step 7: 성공 응답 구성
// ===================================================

const data = $('Check Create Result').first().json;

return [{
  json: {
    success: true,
    data: {
      application_id: data._applicationId,
      status: 'PENDING',
      message: '파트너 신청이 접수되었습니다. 1~3 영업일 이내에 검토 결과를 안내해드릴게요.'
    },
    timestamp: new Date().toISOString()
  }
}];

// ===================================================
// WF-07: 레코드 생성 실패 시 에러 텔레그램 알림
// ===================================================

const data = $input.first().json;

const message = '[파트너 신청 실패] 저장 오류\n\n'
  + (data._telegramError || '알 수 없는 오류');

return [{
  json: {
    ...data,
    _errorTelegramMessage: message
  }
}];
